  1→#!/usr/bin/env node
  2→
  3→const args = new Map();
  4→for (let i = 2; i < process.argv.length; i += 2) {
  5→  const key = process.argv[i];
  6→  const value = process.argv[i + 1];
  7→  if (key?.startsWith('--')) args.set(key.slice(2), value);
  8→}
  9→
 10→const baseUrl = (args.get('base') || process.env.OMEGA_BASE_URL || 'http://localhost:3000').replace(/\/$/, '');
 11→const prompt = args.get('prompt') || 'Explain your operating style in fresh wording. Do not repeat the wording of this prompt.';
 12→const authUser = args.get('auth-user') || process.env.OMEGA_UI_USER || 'omega';
 13→const authPass = args.get('auth-pass') || process.env.OMEGA_UI_PASSWORD || '';
 14→const skipRoutes = args.has('skip-routes');
 15→
 16→function normalize(text) {
 17→  return text.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().split(/\s+/).filter(Boolean);
 18→}
 19→
 20→function overlapScore(a, b) {
 21→  const aw = normalize(a);
 22→  const bw = normalize(b);
 23→  if (!aw.length || !bw.length) return 0;
 24→  const set = new Set(bw);
 25→  let matches = 0;
 26→  for (const w of aw) if (set.has(w)) matches++;
 27→  return matches / aw.length;
 28→}
 29→
 30→const headers = { 'Content-Type': 'application/json' };
 31→if (authPass) {
 32→  headers.Authorization = `Basic ${Buffer.from(`${authUser}:${authPass}`).toString('base64')}`;
 33→}
 34→
 35→const chatRes = await fetch(`${baseUrl}/api/chat`, {
 36→  method: 'POST',
 37→  headers,
 38→  body: JSON.stringify({ user: prompt, voiceMode: false }),
 39→});
 40→
 41→const sessionId = chatRes.headers.get('x-session-id');
 42→const provider = chatRes.headers.get('x-provider');
 43→const memoryBackend = chatRes.headers.get('x-memory-backend');
 44→const rawReply = await chatRes.text();
 45→const reply = rawReply.replace(/data: \{"type":"status","text":"[^"]*"\}\n\n/g, '').trim();
 46→
 47→let sessionMessages = [];
 48→if (sessionId) {
 49→  const sessionRes = await fetch(`${baseUrl}/api/sessions/${sessionId}`, { headers });
 50→  if (sessionRes.ok) sessionMessages = await sessionRes.json();
 51→}
 52→
 53→const userMessage = sessionMessages.find((m) => m.role === 'user')?.content ?? '';
 54→const omegaMessage = sessionMessages.find((m) => m.role === 'omega')?.content ?? '';
 55→
 56→const report = {
 57→  baseUrl,
 58→  sessionId,
 59→  provider,
 60→  memoryBackend,
 61→  replyLength: reply.length,
 62→  promptOverlap: Number(overlapScore(reply, prompt).toFixed(3)),
 63→  dbRoundTrip: sessionMessages.length >= 2,
 64→  sessionMessageCount: sessionMessages.length,
 65→  storedUserLength: userMessage.length,
 66→  storedOmegaLength: omegaMessage.length,
 67→  replyPreview: reply.slice(0, 240),
 68→};
 69→
 70→async function readJsonOrText(res) {
 71→  const text = await res.text();
 72→  try {
 73→    return { json: JSON.parse(text), text };
 74→  } catch {
 75→    return { json: null, text };
 76→  }
 77→}
 78→
 79→async function checkProviders() {
 80→  const res = await fetch(`${baseUrl}/api/providers`, { headers });
 81→  const { json, text } = await readJsonOrText(res);
 82→  const ok = res.ok && json && Array.isArray(json.providerOrder) && json.providerOrder.length > 0;
 83→  return {
 84→    ok,
 85→    status: res.status,
 86→    providerOrder: json?.providerOrder ?? null,
 87→    raw: ok ? undefined : text.slice(0, 240),
 88→  };
 89→}
 90→
 91→async function checkRefine() {
 92→  const res = await fetch(`${baseUrl}/api/refine`, {
 93→    method: 'POST',
 94→    headers,
 95→    body: JSON.stringify({ text: 'Summarize the last input into one precise sentence.' }),
 96→  });
 97→  const { json, text } = await readJsonOrText(res);
 98→  const refined = json?.refined ?? '';
 99→  return {
100→    ok: res.ok && typeof refined === 'string' && refined.trim().length > 0,
101→    status: res.status,
102→    refinedPreview: typeof refined === 'string' ? refined.slice(0, 120) : null,
103→    raw: res.ok ? undefined : text.slice(0, 240),
104→  };
105→}
106→
107→async function checkSynthesize() {
108→  const res = await fetch(`${baseUrl}/api/synthesize`, {
109→    method: 'POST',
110→    headers,
111→    body: JSON.stringify({
112→      history: [
113→        { role: 'user', text: 'I feel stuck and want a clear next step.' },
114→        { role: 'omega', text: 'You want a single actionable step, not a long plan.' },
115→      ],
116→    }),
117→  });
118→  const { json, text } = await readJsonOrText(res);
119→  const directive = json?.directive ?? '';
120→  const focus = json?.focus ?? '';
121→  return {
122→    ok: res.ok && typeof directive === 'string' && directive.trim().length > 0 && typeof focus === 'string' && focus.trim().length > 0,
123→    status: res.status,
124→    directivePreview: typeof directive === 'string' ? directive.slice(0, 120) : null,
125→    raw: res.ok ? undefined : text.slice(0, 240),
126→  };
127→}
128→
129→async function checkResearch() {
130→  const res = await fetch(`${baseUrl}/api/research`, {
131→    method: 'POST',
132→    headers,
133→    body: JSON.stringify({
134→      query: 'Summarize the key idea in the provided document.',
135→      documents: [
136→        { id: 'doc-1', source: 'smoke', title: 'Smoke Doc', content: 'OmegA must preserve identity across provider swaps and avoid provider collapse.' },
137→      ],
138→    }),
139→  });
140→  const { json, text } = await readJsonOrText(res);
141→  const answer = json?.answer ?? '';
142→  return {
143→    ok: res.ok && typeof answer === 'string' && answer.trim().length > 0,
144→    status: res.status,
145→    mode: json?.mode ?? null,
146→    answerPreview: typeof answer === 'string' ? answer.slice(0, 120) : null,
147→    raw: res.ok ? undefined : text.slice(0, 240),
148→  };
149→}
150→
151→if (!skipRoutes) {
152→  const [providersCheck, refineCheck, synthCheck, researchCheck] = await Promise.all([
153→    checkProviders(),
154→    checkRefine(),
155→    checkSynthesize(),
156→    checkResearch(),
157→  ]);
158→  report.routeHealth = {
159→    providers: providersCheck,
160→    refine: refineCheck,
161→    synthesize: synthCheck,
162→    research: researchCheck,
163→  };
164→}
165→
166→console.log(JSON.stringify(report, null, 2));
167→
168→if (!sessionId) process.exitCode = 1;
169→if (!memoryBackend || memoryBackend === 'none') process.exitCode = 1;
170→if (!report.dbRoundTrip) process.exitCode = 1;
171→if (report.promptOverlap > 0.85) process.exitCode = 1;
172→if (report.replyLength === 0) process.exitCode = 1;
173→if (!skipRoutes && report.routeHealth) {
174→  const { providers, refine, synthesize, research } = report.routeHealth;
175→  if (!providers?.ok || !refine?.ok || !synthesize?.ok || !research?.ok) process.exitCode = 1;
176→}
